    private PetFormModel petForm = new();
    private Pet? editingPet;
    private Pet? selectedPet;
    private TreatmentFormModel treatmentForm = new();
    private string newOwnerFirst = string.Empty;
    private string newOwnerLast = string.Empty;
    private string newOwnerPhone = string.Empty;
    private string newOwnerEmail = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).Include(p => p.TreatmentRecords).ToListAsync();
        owners = await Db.Owners.ToListAsync();
        FilterPets();
    }

    private void FilterPets()
    {
        filteredPets = string.IsNullOrWhiteSpace(searchTerm)
            ? pets
            : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
                || p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
                || p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private async Task SavePet()
    {
        int ownerId = petForm.OwnerId;
        if (ownerId == 0)
        {
            var owner = new Owner
            {
                FirstName = newOwnerFirst,
                LastName = newOwnerLast,
                Phone = newOwnerPhone,
                Email = newOwnerEmail
            };
            Db.Owners.Add(owner);
            await Db.SaveChangesAsync();
            ownerId = owner.Id;
        }

        if (editingPet == null)
        {
            var pet = new Pet
            {
                Name = petForm.Name,
                Species = petForm.Species,
                Breed = petForm.Breed,
                DateOfBirth = petForm.DateOfBirth,
                Weight = petForm.Weight,
                Notes = petForm.Notes,
                OwnerId = ownerId
            };
            Db.Pets.Add(pet);
        }
        else
        {
            editingPet.Name = petForm.Name;
            editingPet.Species = petForm.Species;
            editingPet.Breed = petForm.Breed;
            editingPet.DateOfBirth = petForm.DateOfBirth;
            editingPet.Weight = petForm.Weight;
            editingPet.Notes = petForm.Notes;
            editingPet.OwnerId = ownerId;
        }

        await Db.SaveChangesAsync();
        petForm = new();
        editingPet = null;
        newOwnerFirst = newOwnerLast = newOwnerPhone = newOwnerEmail = string.Empty;
        await LoadData();
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        petForm = new PetFormModel
        {
            Name = pet.Name,
            Species = pet.Species,
            Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth,
            Weight = pet.Weight,
            Notes = pet.Notes,
            OwnerId = pet.OwnerId
        };
    }

    private void CancelEdit()
    {
        editingPet = null;
        petForm = new();
    }

    private void ViewHistory(Pet pet)
    {
        selectedPet = pet;
        treatmentForm = new TreatmentFormModel { Date = DateTime.Today };
    }

    private async Task SaveTreatment()
    {
        if (selectedPet == null) return;
        var record = new TreatmentRecord
        {
            PetId = selectedPet.Id,
            Date = treatmentForm.Date,
            Diagnosis = treatmentForm.Diagnosis,
            Treatment = treatmentForm.Treatment,
            Medication = treatmentForm.Medication,
            VeterinarianName = treatmentForm.VeterinarianName,
            Notes = treatmentForm.Notes
        };
        Db.TreatmentRecords.Add(record);
        await Db.SaveChangesAsync();
        selectedPet.TreatmentRecords.Add(record);
        treatmentForm = new TreatmentFormModel { Date = DateTime.Today };
    }

    private class PetFormModel
    {
