@code {
    private List<Pet> pets = new();
    private List<Appointment> appointments = new();
    private Appointment? editingAppointment;
    private AppointmentFormModel apptForm = new();
    private string? conflictMessage;
    private string viewMode = "upcoming";
    private DateTime selectedDate = DateTime.Today;
    private List<TimeSlot> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
        await LoadAvailability();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).ToListAsync();
        appointments = await Db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).OrderBy(a => a.ScheduledDate).ToListAsync();
    }

    private async Task LoadAvailability()
    {
        var dayAppointments = await Db.Appointments
            .Where(a => a.ScheduledDate.Date == selectedDate.Date && a.Status == AppointmentStatus.Scheduled)
            .ToListAsync();

        timeSlots = new();
        for (var hour = 8; hour < 18; hour++)
        {
            for (var min = 0; min < 60; min += 30)
            {
                var time = new TimeSpan(hour, min, 0);
                var slotStart = selectedDate.Date + time;
                var isBooked = dayAppointments.Any(a => a.ScheduledDate < slotStart.AddMinutes(30) && a.ScheduledDate.Add(a.Duration) > slotStart);
                timeSlots.Add(new TimeSlot { Time = time, IsBooked = isBooked });
            }
        }
    }

    private List<Appointment> GetFilteredAppointments() => viewMode switch
    {
        "today" => appointments.Where(a => a.ScheduledDate.Date == DateTime.Today).ToList(),
        "upcoming" => appointments.Where(a => a.ScheduledDate >= DateTime.Now && a.Status == AppointmentStatus.Scheduled).ToList(),
        _ => appointments
    };

    private async Task SaveAppointment()
    {
        conflictMessage = null;
        if (apptForm.PetId == 0) return;

        var start = apptForm.ScheduledDate;
        var end = start.AddMinutes(apptForm.DurationMinutes);
        var hasConflict = await Db.Appointments
            .Where(a => a.Status == AppointmentStatus.Scheduled && a.Id != (editingAppointment?.Id ?? 0))
            .AnyAsync(a => a.ScheduledDate < end && a.ScheduledDate.Add(a.Duration) > start);

        if (hasConflict)
        {
            conflictMessage = "Time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment == null)
        {
            var appt = new Appointment
            {
                PetId = apptForm.PetId,
                ScheduledDate = apptForm.ScheduledDate,
                Duration = TimeSpan.FromMinutes(apptForm.DurationMinutes),
                Reason = apptForm.Reason,
                Notes = apptForm.Notes
            };
            Db.Appointments.Add(appt);
        }
        else
        {
            editingAppointment.PetId = apptForm.PetId;
            editingAppointment.ScheduledDate = apptForm.ScheduledDate;
            editingAppointment.Duration = TimeSpan.FromMinutes(apptForm.DurationMinutes);
            editingAppointment.Reason = apptForm.Reason;
            editingAppointment.Notes = apptForm.Notes;
        }

        await Db.SaveChangesAsync();
        apptForm = new();
        editingAppointment = null;
        await LoadData();
        await LoadAvailability();
    }

    private void Reschedule(Appointment appt)
    {
        editingAppointment = appt;
        apptForm = new AppointmentFormModel
        {
            PetId = appt.PetId,
            ScheduledDate = appt.ScheduledDate,
            DurationMinutes = (int)appt.Duration.TotalMinutes,
            Reason = appt.Reason,
            Notes = appt.Notes
        };
    }

    private async Task Complete(Appointment appt)
    {
        appt.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadData();
        await LoadAvailability();
    }

    private async Task Cancel(Appointment appt)
    {
        appt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadData();
        await LoadAvailability();
    }

    private void CancelEdit()
    {
        editingAppointment = null;
        apptForm = new();
        conflictMessage = null;
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        AppointmentStatus.NoShow => "bg-warning",
        _ => "bg-secondary"
    };

    private class AppointmentFormModel
    {
        public int PetId { get; set; }
        public DateTime ScheduledDate { get; set; } = DateTime.Now.Date.AddHours(9);
        public int DurationMinutes { get; set; } = 30;
        public string Reason { get; set; } = string.Empty;
        public string Notes { get; set; } = string.Empty;
    }

    private class TimeSlot
    {
        public TimeSpan Time { get; set; }
        public bool IsBooked { get; set; }
    }
}
```

