    private int petCount;
    private int ownerCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<Appointment> upcomingAppointments = new();
    private List<TreatmentRecord> recentTreatments = new();

    protected override async Task OnInitializedAsync()
    {
        petCount = await Db.Pets.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        todayAppointments = await Db.Appointments
            .Where(a => a.ScheduledDate.Date == DateTime.Today && a.Status == AppointmentStatus.Scheduled)
            .CountAsync();
        pendingInvoices = await Db.Invoices
            .Where(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue)
            .CountAsync();
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledDate >= DateTime.Now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledDate)
            .Take(5)
            .ToListAsync();
        recentTreatments = await Db.TreatmentRecords
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}
