                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="apptForm.ScheduledDate" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Duration (minutes)</label>
                        <InputNumber class="form-control" @bind-Value="apptForm.DurationMinutes" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="apptForm.Reason" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="apptForm.Notes" />
                    </div>
                    @if (conflictMessage != null)
                    {
                        <div class="alert alert-warning">@conflictMessage</div>
                    }
                    <button type="submit" class="btn btn-primary">@(editingAppointment == null ? "Schedule" : "Update")</button>
                    @if (editingAppointment != null)
                    {
                        <button type="button" class="btn btn-secondary ms-2" @onclick="CancelEdit">Cancel</button>
                    }
                </EditForm>
            </div>
        </div>

        <div class="card mt-3">
            <div class="card-header"><h5 class="mb-0">Availability — @selectedDate.ToString("d")</h5></div>
            <div class="card-body">
                <InputDate class="form-control mb-2" @bind-Value="selectedDate" @bind-Value:after="LoadAvailability" />
                @if (timeSlots.Any())
                {
                    <div class="list-group">
                        @foreach (var slot in timeSlots)
                        {
                            <div class="list-group-item d-flex justify-content-between align-items-center @(slot.IsBooked ? "list-group-item-danger" : "list-group-item-success")">
                                @slot.Time.ToString("hh\\:mm")
                                <span class="badge @(slot.IsBooked ? "bg-danger" : "bg-success")">
                                    @(slot.IsBooked ? "Booked" : "Available")
                                </span>
                            </div>
                        }
                    </div>
                }
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <ul class="nav nav-tabs mb-3">
            <li class="nav-item">
                <button class="nav-link @(viewMode == "upcoming" ? "active" : "")" @onclick='() => viewMode = "upcoming"'>Upcoming</button>
            </li>
            <li class="nav-item">
                <button class="nav-link @(viewMode == "today" ? "active" : "")" @onclick='() => viewMode = "today"'>Today</button>
            </li>
            <li class="nav-item">
                <button class="nav-link @(viewMode == "all" ? "active" : "")" @onclick='() => viewMode = "all"'>All</button>
            </li>
        </ul>

        <table class="table table-striped">
