@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mt-3">
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">@(editingPet == null ? "Register New Pet" : "Edit Pet")</h5>
            </div>
            <div class="card-body">
                <EditForm Model="petForm" OnValidSubmit="SavePet" FormName="petForm">
                    <DataAnnotationsValidator />
                    <div class="mb-2">
                        <label class="form-label">Owner</label>
                        <select class="form-select" @bind="petForm.OwnerId">
                            <option value="0">-- Select or add new --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                            }
                        </select>
                    </div>
                    @if (petForm.OwnerId == 0)
                    {
                        <div class="mb-2">
                            <label class="form-label">Owner First Name</label>
                            <InputText class="form-control" @bind-Value="newOwnerFirst" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Owner Last Name</label>
                            <InputText class="form-control" @bind-Value="newOwnerLast" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Owner Phone</label>
                            <InputText class="form-control" @bind-Value="newOwnerPhone" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Owner Email</label>
                            <InputText class="form-control" @bind-Value="newOwnerEmail" />
                        </div>
                    }
                    <hr />
                    <div class="mb-2">
                        <label class="form-label">Pet Name</label>
                        <InputText class="form-control" @bind-Value="petForm.Name" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="petForm.Species" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="petForm.Breed" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="petForm.DateOfBirth" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="petForm.Weight" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="petForm.Notes" />
                    </div>
                    <button type="submit" class="btn btn-primary">@(editingPet == null ? "Register" : "Update")</button>
                    @if (editingPet != null)
                    {
                        <button type="button" class="btn btn-secondary ms-2" @onclick="CancelEdit">Cancel</button>
                    }
                </EditForm>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="mb-3">
            <input type="text" class="form-control" placeholder="Search pets..." @bind="searchTerm" @bind:event="oninput" @bind:after="FilterPets" />
        </div>
        <table class="table table-striped">
            <thead>
                <tr><th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var pet in filteredPets)
                {
                    <tr>
                        <td>@pet.Name</td>
                        <td>@pet.Species</td>
                        <td>@pet.Breed</td>
                        <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                            <button class="btn btn-sm btn-outline-info" @onclick="() => ViewHistory(pet)">History</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@if (selectedPet != null)
{
    <div class="row mt-4">
        <div class="col-12">
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Medical History — @selectedPet.Name</h5>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => selectedPet = null">Close</button>
                </div>
                <div class="card-body">
                    <h6>Add Treatment Note</h6>
                    <EditForm Model="treatmentForm" OnValidSubmit="SaveTreatment" FormName="treatmentForm">
                        <div class="row mb-2">
                            <div class="col-md-3">
                                <InputDate class="form-control" @bind-Value="treatmentForm.Date" />
                            </div>
                            <div class="col-md-3">
                                <InputText class="form-control" placeholder="Diagnosis" @bind-Value="treatmentForm.Diagnosis" />
                            </div>
                            <div class="col-md-3">
                                <InputText class="form-control" placeholder="Treatment" @bind-Value="treatmentForm.Treatment" />
                            </div>
                            <div class="col-md-3">
                                <InputText class="form-control" placeholder="Medication" @bind-Value="treatmentForm.Medication" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <InputText class="form-control" placeholder="Veterinarian" @bind-Value="treatmentForm.VeterinarianName" />
                            </div>
                            <div class="col-md-6">
                                <InputText class="form-control" placeholder="Notes" @bind-Value="treatmentForm.Notes" />
                            </div>
                        </div>
                        <button type="submit" class="btn btn-success btn-sm">Add Treatment</button>
                    </EditForm>

                    <hr />
                    <table class="table table-sm mt-3">
                        <thead><tr><th>Date</th><th>Diagnosis</th><th>Treatment</th><th>Medication</th><th>Vet</th><th>Notes</th></tr></thead>
                        <tbody>
                            @foreach (var record in selectedPet.TreatmentRecords.OrderByDescending(t => t.Date))
                            {
                                <tr>
                                    <td>@record.Date.ToString("d")</td>
                                    <td>@record.Diagnosis</td>
