            await Db.SaveChangesAsync();
            ownerId = owner.Id;
        }

        if (editingPet == null)
        {
            var pet = new Pet
            {
                Name = petForm.Name,
                Species = petForm.Species,
                Breed = petForm.Breed,
                DateOfBirth = petForm.DateOfBirth,
                Weight = petForm.Weight,
                Notes = petForm.Notes,
                OwnerId = ownerId
            };
            Db.Pets.Add(pet);
