        <div class="card">
            <div class="card-header"><h5 class="mb-0">Generate Invoice</h5></div>
            <div class="card-body">
                <EditForm Model="invoiceForm" OnValidSubmit="CreateInvoice" FormName="invoiceForm">
                    <div class="mb-2">
                        <label class="form-label">Pet</label>
                        <select class="form-select" @bind="invoiceForm.PetId">
                            <option value="0">-- Select pet --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputTextArea class="form-control" @bind-Value="invoiceForm.Description" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Amount</label>
                        <InputNumber class="form-control" @bind-Value="invoiceForm.Amount" />
                    </div>
                    <div class="mb-2">
