@code {
    private List<Pet> pets = new();
    private List<Invoice> invoices = new();
    private List<Payment> payments = new();
    private string tab = "invoices";
    private InvoiceFormModel invoiceForm = new();
    private Invoice? payingInvoice;
    private PaymentFormModel paymentForm = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).ToListAsync();
        invoices = await Db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner).Include(i => i.Payments).OrderByDescending(i => i.IssuedDate).ToListAsync();
        payments = await Db.Payments.Include(p => p.Invoice).OrderByDescending(p => p.PaymentDate).ToListAsync();
    }

    private async Task CreateInvoice()
    {
        if (invoiceForm.PetId == 0) return;
        var tax = invoiceForm.Amount * invoiceForm.TaxPercent / 100;
        var invoice = new Invoice
        {
            PetId = invoiceForm.PetId,
            Description = invoiceForm.Description,
            Amount = invoiceForm.Amount,
            Tax = tax,
            TotalAmount = invoiceForm.Amount + tax,
            DueDate = invoiceForm.DueDate,
            IssuedDate = DateTime.Now
        };
        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        invoiceForm = new();
        await LoadData();
    }

    private void ShowPaymentForm(Invoice invoice)
    {
        payingInvoice = invoice;
        paymentForm = new PaymentFormModel { Amount = GetOutstanding(invoice) };
    }

    private async Task ProcessPayment()
    {
        if (payingInvoice == null) return;
        var payment = new Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = paymentForm.Amount,
            Method = paymentForm.Method,
            Reference = paymentForm.Reference,
            Notes = paymentForm.Notes,
            PaymentDate = DateTime.Now
        };
        Db.Payments.Add(payment);

        var totalPaid = payingInvoice.Payments.Sum(p => p.Amount) + paymentForm.Amount;
        payingInvoice.Status = totalPaid >= payingInvoice.TotalAmount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;

        await Db.SaveChangesAsync();
        payingInvoice = null;
        paymentForm = new();
        await LoadData();
    }

    private async Task CancelInvoice(Invoice invoice)
    {
        invoice.Status = InvoiceStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadData();
    }

    private decimal GetOutstanding(Invoice invoice)
    {
        return invoice.TotalAmount - invoice.Payments.Sum(p => p.Amount);
    }

    private string GetInvoiceStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };

    private class InvoiceFormModel
    {
        public int PetId { get; set; }
        public string Description { get; set; } = string.Empty;
        public decimal Amount { get; set; }
        public decimal TaxPercent { get; set; } = 10;
        public DateTime? DueDate { get; set; } = DateTime.Today.AddDays(30);
    }

    private class PaymentFormModel
    {
        public decimal Amount { get; set; }
        public PaymentMethod Method { get; set; } = PaymentMethod.Cash;
        public string Reference { get; set; } = string.Empty;
        public string Notes { get; set; } = string.Empty;
    }
}

