@code {
    private List<Pet> pets = new();
    private List<Pet> filteredPets = new();
    private List<Owner> owners = new();
    private string searchTerm = string.Empty;
    private PetFormModel petForm = new();
    private Pet? editingPet;
    private Pet? selectedPet;
    private TreatmentFormModel treatmentForm = new();
    private string newOwnerFirst = string.Empty;
    private string newOwnerLast = string.Empty;
    private string newOwnerPhone = string.Empty;
    private string newOwnerEmail = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).Include(p => p.TreatmentRecords).ToListAsync();
        owners = await Db.Owners.ToListAsync();
        FilterPets();
    }

    private void FilterPets()
    {
        filteredPets = string.IsNullOrWhiteSpace(searchTerm)
            ? pets
            : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
                || p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
                || p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private async Task SavePet()
    {
        int ownerId = petForm.OwnerId;
        if (ownerId == 0)
        {
            var owner = new Owner
            {
                FirstName = newOwnerFirst,
                LastName = newOwnerLast,
                Phone = newOwnerPhone,
                Email = newOwnerEmail
            };
            Db.Owners.Add(owner);
            await Db.SaveChangesAsync();
            ownerId = owner.Id;
        }

        if (editingPet == null)
        {
            var pet = new Pet
            {
                Name = petForm.Name,
                Species = petForm.Species,
                Breed = petForm.Breed,
                DateOfBirth = petForm.DateOfBirth,
                Weight = petForm.Weight,
                Notes = petForm.Notes,
                OwnerId = ownerId
            };
            Db.Pets.Add(pet);
        }
        else
        {
            editingPet.Name = petForm.Name;
            editingPet.Species = petForm.Species;
            editingPet.Breed = petForm.Breed;
            editingPet.DateOfBirth = petForm.DateOfBirth;
            editingPet.Weight = petForm.Weight;
            editingPet.Notes = petForm.Notes;
            editingPet.OwnerId = ownerId;
        }

        await Db.SaveChangesAsync();
        petForm = new();
        editingPet = null;
        newOwnerFirst = newOwnerLast = newOwnerPhone = newOwnerEmail = string.Empty;
        await LoadData();
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        petForm = new PetFormModel
        {
            Name = pet.Name,
            Species = pet.Species,
            Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth,
            Weight = pet.Weight,
            Notes = pet.Notes,
            OwnerId = pet.OwnerId
        };
    }

    private void CancelEdit()
    {
        editingPet = null;
        petForm = new();
    }

    private void ViewHistory(Pet pet)
    {
        selectedPet = pet;
        treatmentForm = new TreatmentFormModel { Date = DateTime.Today };
    }

    private async Task SaveTreatment()
    {
        if (selectedPet == null) return;
        var record = new TreatmentRecord
        {
            PetId = selectedPet.Id,
            Date = treatmentForm.Date,
            Diagnosis = treatmentForm.Diagnosis,
            Treatment = treatmentForm.Treatment,
            Medication = treatmentForm.Medication,
            VeterinarianName = treatmentForm.VeterinarianName,
            Notes = treatmentForm.Notes
        };
        Db.TreatmentRecords.Add(record);
        await Db.SaveChangesAsync();
        selectedPet.TreatmentRecords.Add(record);
        treatmentForm = new TreatmentFormModel { Date = DateTime.Today };
    }

    private class PetFormModel
    {
        public string Name { get; set; } = string.Empty;
        public string Species { get; set; } = string.Empty;
        public string Breed { get; set; } = string.Empty;
        public DateTime? DateOfBirth { get; set; }
        public decimal Weight { get; set; }
        public string Notes { get; set; } = string.Empty;
        public int OwnerId { get; set; }
    }

    private class TreatmentFormModel
    {
        public DateTime Date { get; set; } = DateTime.Today;
        public string Diagnosis { get; set; } = string.Empty;
        public string Treatment { get; set; } = string.Empty;
        public string Medication { get; set; } = string.Empty;
        public string VeterinarianName { get; set; } = string.Empty;
        public string Notes { get; set; } = string.Empty;
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mt-3">
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">@(editingAppointment == null ? "New Appointment" : "Edit Appointment")</h5>
            </div>
            <div class="card-body">
                <EditForm Model="apptForm" OnValidSubmit="SaveAppointment" FormName="apptForm">
                    <div class="mb-2">
                        <label class="form-label">Pet</label>
                        <select class="form-select" @bind="apptForm.PetId">
                            <option value="0">-- Select pet --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="apptForm.ScheduledDate" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Duration (minutes)</label>
                        <InputNumber class="form-control" @bind-Value="apptForm.DurationMinutes" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="apptForm.Reason" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="apptForm.Notes" />
                    </div>
                    @if (conflictMessage != null)
                    {
                        <div class="alert alert-warning">@conflictMessage</div>
                    }
                    <button type="submit" class="btn btn-primary">@(editingAppointment == null ? "Schedule" : "Update")</button>
                    @if (editingAppointment != null)
                    {
                        <button type="button" class="btn btn-secondary ms-2" @onclick="CancelEdit">Cancel</button>
                    }
                </EditForm>
            </div>
        </div>

        <div class="card mt-3">
            <div class="card-header"><h5 class="mb-0">Availability — @selectedDate.ToString("d")</h5></div>
            <div class="card-body">
                <InputDate class="form-control mb-2" @bind-Value="selectedDate" @bind-Value:after="LoadAvailability" />
                @if (timeSlots.Any())
                {
                    <div class="list-group">
                        @foreach (var slot in timeSlots)
                        {
                            <div class="list-group-item d-flex justify-content-between align-items-center @(slot.IsBooked ? "list-group-item-danger" : "list-group-item-success")">
                                @slot.Time.ToString("hh\\:mm")
                                <span class="badge @(slot.IsBooked ? "bg-danger" : "bg-success")">
                                    @(slot.IsBooked ? "Booked" : "Available")
                                </span>
                            </div>
                        }
                    </div>
                }
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <ul class="nav nav-tabs mb-3">
            <li class="nav-item">
                <button class="nav-link @(viewMode == "upcoming" ? "active" : "")" @onclick='() => viewMode = "upcoming"'>Upcoming</button>
            </li>
            <li class="nav-item">
                <button class="nav-link @(viewMode == "today" ? "active" : "")" @onclick='() => viewMode = "today"'>Today</button>
            </li>
            <li class="nav-item">
                <button class="nav-link @(viewMode == "all" ? "active" : "")" @onclick='() => viewMode = "all"'>All</button>
            </li>
        </ul>

        <table class="table table-striped">
            <thead><tr><th>Date/Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
                @foreach (var appt in GetFilteredAppointments())
                {
                    <tr>
                        <td>@appt.ScheduledDate.ToString("g")</td>
                        <td>@appt.Pet.Name</td>
                        <td>@appt.Pet.Owner.LastName</td>
                        <td>@appt.Reason</td>
                        <td><span class="badge @GetStatusBadge(appt.Status)">@appt.Status</span></td>
                        <td>
                            @if (appt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(appt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(appt)">Complete</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(appt)">Cancel</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    private List<Pet> pets = new();
    private List<Appointment> appointments = new();
    private Appointment? editingAppointment;
    private AppointmentFormModel apptForm = new();
    private string? conflictMessage;
    private string viewMode = "upcoming";
    private DateTime selectedDate = DateTime.Today;
    private List<TimeSlot> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
        await LoadAvailability();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).ToListAsync();
        appointments = await Db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).OrderBy(a => a.ScheduledDate).ToListAsync();
    }

    private async Task LoadAvailability()
    {
        var dayAppointments = await Db.Appointments
            .Where(a => a.ScheduledDate.Date == selectedDate.Date && a.Status == AppointmentStatus.Scheduled)
            .ToListAsync();

        timeSlots = new();
        for (var hour = 8; hour < 18; hour++)
        {
            for (var min = 0; min < 60; min += 30)
            {
                var time = new TimeSpan(hour, min, 0);
                var slotStart = selectedDate.Date + time;
                var isBooked = dayAppointments.Any(a => a.ScheduledDate < slotStart.AddMinutes(30) && a.ScheduledDate.Add(a.Duration) > slotStart);
                timeSlots.Add(new TimeSlot { Time = time, IsBooked = isBooked });
            }
        }
    }

    private List<Appointment> GetFilteredAppointments() => viewMode switch
    {
        "today" => appointments.Where(a => a.ScheduledDate.Date == DateTime.Today).ToList(),
        "upcoming" => appointments.Where(a => a.ScheduledDate >= DateTime.Now && a.Status == AppointmentStatus.Scheduled).ToList(),
        _ => appointments
    };

    private async Task SaveAppointment()
    {
        conflictMessage = null;
        if (apptForm.PetId == 0) return;

        var start = apptForm.ScheduledDate;
        var end = start.AddMinutes(apptForm.DurationMinutes);
        var hasConflict = await Db.Appointments
            .Where(a => a.Status == AppointmentStatus.Scheduled && a.Id != (editingAppointment?.Id ?? 0))
            .AnyAsync(a => a.ScheduledDate < end && a.ScheduledDate.Add(a.Duration) > start);

        if (hasConflict)
        {
            conflictMessage = "Time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment == null)
        {
            var appt = new Appointment
            {
                PetId = apptForm.PetId,
                ScheduledDate = apptForm.ScheduledDate,
                Duration = TimeSpan.FromMinutes(apptForm.DurationMinutes),
                Reason = apptForm.Reason,
                Notes = apptForm.Notes
            };
            Db.Appointments.Add(appt);
        }
        else
        {
            editingAppointment.PetId = apptForm.PetId;
            editingAppointment.ScheduledDate = apptForm.ScheduledDate;
            editingAppointment.Duration = TimeSpan.FromMinutes(apptForm.DurationMinutes);
            editingAppointment.Reason = apptForm.Reason;
            editingAppointment.Notes = apptForm.Notes;
        }

        await Db.SaveChangesAsync();
        apptForm = new();
        editingAppointment = null;
        await LoadData();
        await LoadAvailability();
    }

    private void Reschedule(Appointment appt)
    {
        editingAppointment = appt;
        apptForm = new AppointmentFormModel
        {
            PetId = appt.PetId,
            ScheduledDate = appt.ScheduledDate,
            DurationMinutes = (int)appt.Duration.TotalMinutes,
            Reason = appt.Reason,
            Notes = appt.Notes
        };
    }

    private async Task Complete(Appointment appt)
    {
        appt.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadData();
        await LoadAvailability();
    }

    private async Task Cancel(Appointment appt)
    {
        appt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadData();
        await LoadAvailability();
    }

    private void CancelEdit()
    {
        editingAppointment = null;
        apptForm = new();
        conflictMessage = null;
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        AppointmentStatus.NoShow => "bg-warning",
        _ => "bg-secondary"
    };

    private class AppointmentFormModel
    {
        public int PetId { get; set; }
        public DateTime ScheduledDate { get; set; } = DateTime.Now.Date.AddHours(9);
        public int DurationMinutes { get; set; } = 30;
        public string Reason { get; set; } = string.Empty;
        public string Notes { get; set; } = string.Empty;
    }

    private class TimeSlot
    {
        public TimeSpan Time { get; set; }
        public bool IsBooked { get; set; }
    }
}

@page "/billing"
