            <div class="card-body">
                <EditForm Model="invoiceForm" OnValidSubmit="CreateInvoice" FormName="invoiceForm">
                    <div class="mb-2">
                        <label class="form-label">Pet</label>
                        <select class="form-select" @bind="invoiceForm.PetId">
