                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputTextArea class="form-control" @bind-Value="invoiceForm.Description" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Amount</label>
                        <InputNumber class="form-control" @bind-Value="invoiceForm.Amount" />
                    </div>
                    <div class="mb-2">
