            <li class="nav-item">
                <button class="nav-link @(tab == "invoices" ? "active" : "")" @onclick='() => tab = "invoices"'>Invoices</button>
            </li>
            <li class="nav-item">
                <button class="nav-link @(tab == "payments" ? "active" : "")" @onclick='() => tab = "payments"'>Payment History</button>
