+
+    private async Task SaveAppointment()
+    {
+        conflictMessage = null;
+        if (apptForm.PetId == 0) return;
+
+        var start = apptForm.ScheduledDate;
+        var end = start.AddMinutes(apptForm.DurationMinutes);
+        var hasConflict = await Db.Appointments
+            .Where(a => a.Status == AppointmentStatus.Scheduled && a.Id != (editingAppointment?.Id ?? 0))
+            .AnyAsync(a => a.ScheduledDate < end && a.ScheduledDate.Add(a.Duration) > start);
+
+        if (hasConflict)
+        {
+            conflictMessage = "Time slot conflicts with an existing appointment.";
+            return;
+        }
+
+        if (editingAppointment == null)
+        {
+            var appt = new Appointment
+            {
+                PetId = apptForm.PetId,
+                ScheduledDate = apptForm.ScheduledDate,
+                Duration = TimeSpan.FromMinutes(apptForm.DurationMinutes),
+                Reason = apptForm.Reason,
+                Notes = apptForm.Notes
+            };
+            Db.Appointments.Add(appt);
+        }
+        else
+        {
+            editingAppointment.PetId = apptForm.PetId;
+            editingAppointment.ScheduledDate = apptForm.ScheduledDate;
+            editingAppointment.Duration = TimeSpan.FromMinutes(apptForm.DurationMinutes);
+            editingAppointment.Reason = apptForm.Reason;
+            editingAppointment.Notes = apptForm.Notes;
+        }
+
+        await Db.SaveChangesAsync();
+        apptForm = new();
+        editingAppointment = null;
+        await LoadData();
+        await LoadAvailability();
+    }
+
+    private void Reschedule(Appointment appt)
+    {
+        editingAppointment = appt;
+        apptForm = new AppointmentFormModel
+        {
+            PetId = appt.PetId,
+            ScheduledDate = appt.ScheduledDate,
+            DurationMinutes = (int)appt.Duration.TotalMinutes,
+            Reason = appt.Reason,
+            Notes = appt.Notes
+        };
+    }
+
+    private async Task Complete(Appointment appt)
+    {
+        appt.Status = AppointmentStatus.Completed;
+        await Db.SaveChangesAsync();
+        await LoadData();
+        await LoadAvailability();
+    }
+
+    private async Task Cancel(Appointment appt)
+    {
+        appt.Status = AppointmentStatus.Cancelled;
+        await Db.SaveChangesAsync();
+        await LoadData();
+        await LoadAvailability();
+    }
