+    }
+
+    private async Task LoadData()
+    {
+        pets = await Db.Pets.Include(p => p.Owner).ToListAsync();
+        invoices = await Db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner).Include(i => i.Payments).OrderByDescending(i => i.IssuedDate).ToListAsync();
+        payments = await Db.Payments.Include(p => p.Invoice).OrderByDescending(p => p.PaymentDate).ToListAsync();
+    }
+
+    private async Task CreateInvoice()
+    {
+        if (invoiceForm.PetId == 0) return;
+        var tax = invoiceForm.Amount * invoiceForm.TaxPercent / 100;
+        var invoice = new Invoice
+        {
+            PetId = invoiceForm.PetId,
+            Description = invoiceForm.Description,
+            Amount = invoiceForm.Amount,
+            Tax = tax,
+            TotalAmount = invoiceForm.Amount + tax,
+            DueDate = invoiceForm.DueDate,
+            IssuedDate = DateTime.Now
+        };
+        Db.Invoices.Add(invoice);
+        await Db.SaveChangesAsync();
+        invoiceForm = new();
+        await LoadData();
+    }
