@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>VetClinic Dashboard</PageTitle>

<h1>Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
                <a href="/patients" class="btn btn-light btn-sm">Manage</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
                <a href="/appointments" class="btn btn-light btn-sm">View</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
                <a href="/billing" class="btn btn-light btn-sm">View</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
                <a href="/patients" class="btn btn-light btn-sm">Manage</a>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Upcoming Appointments</h5>
                <a href="/appointments" class="btn btn-outline-primary btn-sm">View All</a>
            </div>
            <div class="card-body">
                @if (upcomingAppointments.Any())
                {
                    <table class="table table-sm">
                        <thead><tr><th>Time</th><th>Pet</th><th>Reason</th></tr></thead>
                        <tbody>
                            @foreach (var apt in upcomingAppointments)
                            {
                                <tr>
                                    <td>@apt.ScheduledDate.ToString("g")</td>
                                    <td>@apt.Pet.Name</td>
                                    <td>@apt.Reason</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No upcoming appointments.</p>
                }
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Recent Treatments</h5>
                <a href="/patients" class="btn btn-outline-primary btn-sm">View All</a>
            </div>
            <div class="card-body">
                @if (recentTreatments.Any())
                {
                    <table class="table table-sm">
                        <thead><tr><th>Date</th><th>Pet</th><th>Treatment</th></tr></thead>
                        <tbody>
                            @foreach (var t in recentTreatments)
                            {
                                <tr>
                                    <td>@t.Date.ToString("d")</td>
                                    <td>@t.Pet.Name</td>
                                    <td>@t.Treatment</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No recent treatments.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int petCount;
    private int ownerCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<Appointment> upcomingAppointments = new();
    private List<TreatmentRecord> recentTreatments = new();

    protected override async Task OnInitializedAsync()
    {
        petCount = await Db.Pets.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        todayAppointments = await Db.Appointments
            .Where(a => a.ScheduledDate.Date == DateTime.Today && a.Status == AppointmentStatus.Scheduled)
            .CountAsync();
        pendingInvoices = await Db.Invoices
            .Where(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue)
            .CountAsync();
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledDate >= DateTime.Now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledDate)
            .Take(5)
            .ToListAsync();
        recentTreatments = await Db.TreatmentRecords
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}
```

### 5. Create Patients page
Create `Components/Pages/Patients.razor`:
```razor
@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mt-3">
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">@(editingPet == null ? "Register New Pet" : "Edit Pet")</h5>
            </div>
            <div class="card-body">
                <EditForm Model="petForm" OnValidSubmit="SavePet" FormName="petForm">
                    <DataAnnotationsValidator />
                    <div class="mb-2">
                        <label class="form-label">Owner</label>
                        <select class="form-select" @bind="petForm.OwnerId">
                            <option value="0">-- Select or add new --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                            }
                        </select>
                    </div>
                    @if (petForm.OwnerId == 0)
                    {
                        <div class="mb-2">
                            <label class="form-label">Owner First Name</label>
                            <InputText class="form-control" @bind-Value="newOwnerFirst" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Owner Last Name</label>
                            <InputText class="form-control" @bind-Value="newOwnerLast" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Owner Phone</label>
                            <InputText class="form-control" @bind-Value="newOwnerPhone" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Owner Email</label>
                            <InputText class="form-control" @bind-Value="newOwnerEmail" />
                        </div>
                    }
                    <hr />
                    <div class="mb-2">
                        <label class="form-label">Pet Name</label>
                        <InputText class="form-control" @bind-Value="petForm.Name" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="petForm.Species" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="petForm.Breed" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="petForm.DateOfBirth" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="petForm.Weight" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="petForm.Notes" />
                    </div>
                    <button type="submit" class="btn btn-primary">@(editingPet == null ? "Register" : "Update")</button>
                    @if (editingPet != null)
                    {
                        <button type="button" class="btn btn-secondary ms-2" @onclick="CancelEdit">Cancel</button>
                    }
                </EditForm>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="mb-3">
            <input type="text" class="form-control" placeholder="Search pets..." @bind="searchTerm" @bind:event="oninput" @bind:after="FilterPets" />
        </div>
        <table class="table table-striped">
            <thead>
                <tr><th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var pet in filteredPets)
                {
                    <tr>
                        <td>@pet.Name</td>
                        <td>@pet.Species</td>
                        <td>@pet.Breed</td>
                        <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
