                    </EditForm>

                    <hr />
                    <table class="table table-sm mt-3">
                        <thead><tr><th>Date</th><th>Diagnosis</th><th>Treatment</th><th>Medication</th><th>Vet</th><th>Notes</th></tr></thead>
